                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Film, Download, RotateCcw, Settings2, MonitorPlay, Globe, Square, RefreshCw, Play, Pause, RotateCw, Volume2, VolumeX, Maximize2, Minimize2, Gauge } from 'lucide-react';
import { Chapter, FileContext } from '../types';
import { generateSummaryVideo, hasValidKeyForVeo, requestVeoKey } from '../services/gemini';
import { Loader } from './ui/Loader';

interface Props {
  chapter: Chapter;
  fileContext: FileContext;
}

const STYLES = [
  'Cinematic', 'Anime', 'Photorealistic', 'Cartoon', 'Cyberpunk', 
  'Vaporwave', 'Noir', 'Documentary', 'Surreal'
];

const LANGUAGES = [
  'Original', 'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'
];

const RESOLUTIONS: ('720p' | '1080p' | '4K')[] = ['720p', '1080p', '4K'];
const SPEEDS = [0.5, 0.75, 1.0, 1.25, 1.5, 2.0];

export const VideoSummary: React.FC<Props> = ({ chapter, fileContext }) => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<string>("");
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('Cinematic');
  const [selectedLanguage, setSelectedLanguage] = useState('Original');
  const [selectedResolution, setSelectedResolution] = useState<'720p' | '1080p' | '4K'>('720p');

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playbackRate, setPlaybackRate] = useState(1.0);
  const [isMuted, setIsMuted] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const [controlsVisible, setControlsVisible] = useState(true);

  const abortRef = useRef<boolean>(false);
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const controlsTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    return () => {
      if (videoUrl) URL.revokeObjectURL(videoUrl);
    };
  }, [videoUrl]);

  const handleToggleGeneration = async () => {
    if (isGenerating) {
        abortRef.current = true;
        setIsGenerating(false);
        setStatus("");
        return;
    }
    setError(null);
    setIsGenerating(true);
    abortRef.current = false;
    setStatus("Authenticating & Generating...");
    try {
      const hasKey = await hasValidKeyForVeo();
      if (!hasKey) {
        setStatus("Waiting for Access Key...");
        await requestVeoKey();
      }
      if (abortRef.current) return;

      const targetLang = selectedLanguage === 'Original' ? 'the source language of the document' : selectedLanguage;
      const url = await generateSummaryVideo(
        fileContext, 
        chapter, 
        setStatus, 
        selectedStyle, 
        targetLang,
        selectedResolution === '4K' ? '1080p' : selectedResolution as any
      );

      if (!abortRef.current) {
        if (videoUrl) URL.revokeObjectURL(videoUrl);
        setVideoUrl(url);
        setIsPlaying(false);
      }
    } catch (e: any) {
      if (!abortRef.current) {
        console.error(e);
        let msg = "Generation failed.";
        if (e.message?.includes("Requested entity was not found")) {
            msg = "Key Invalid. Paid project key required.";
            await requestVeoKey();
        } else if (e.message) msg = e.message;
        setError(msg);
      }
    } finally {
      if (!abortRef.current) {
        setIsGenerating(false);
        setStatus("");
      }
    }
  };

  const togglePlay = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!videoRef.current || !videoUrl) return;

    try {
      if (isPlaying) {
        videoRef.current.pause();
        setIsPlaying(false);
      } else {
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          await playPromise;
          setIsPlaying(true);
        }
      }
    } catch (err) {
      console.warn("Playback interrupted or failed:", err);
      setIsPlaying(false);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    if (videoRef.current && duration) {
       videoRef.current.currentTime = (val / 100) * duration;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (videoRef.current) {
        videoRef.current.muted = !isMuted;
        setIsMuted(!isMuted);
    }
  };

  const toggleFullScreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
        containerRef.current.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
  };

  const resetControlsTimeout = () => {
    setControlsVisible(true);
    if (controlsTimeoutRef.current) {
      window.clearTimeout(controlsTimeoutRef.current);
    }
    if (isPlaying) {
      controlsTimeoutRef.current = window.setTimeout(() => {
        setControlsVisible(false);
      }, 3000);
    }
  };

  useEffect(() => {
    const handleFsChange = () => {
      const isFs = !!document.fullscreenElement;
      setIsFullScreen(isFs);
      if (!isFs) setControlsVisible(true);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const formatTime = (seconds: number): string => {
    if (!seconds || isNaN(seconds)) return "00:00";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateProgress = () => {
    if (videoRef.current) {
        setCurrentTime(videoRef.current.currentTime);
        setDuration(videoRef.current.duration || 0);
        setPlaybackProgress((videoRef.current.currentTime / (videoRef.current.duration || 1)) * 100);
    }
  };

  useEffect(() => {
    if (videoRef.current) {
        videoRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate, videoUrl]);

  const currentStatusLabel = isGenerating ? "STOP" : videoUrl ? "REGENERATE" : "INITIATE";
  const currentStatusIcon = isGenerating ? <Square size={14} fill="currentColor" /> : videoUrl ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />;

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left overflow-hidden">
      <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-wrap gap-2 z-20">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs">
                 <MonitorPlay size={18} className="text-[#00f3ff]" />
                 <span>Cine_Render</span>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="flex items-center gap-1">
                    <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                    <select value={selectedStyle} onChange={(e) => setSelectedStyle(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{STYLES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 </div>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="flex items-center gap-1">
                    <div className="p-1.5 text-zinc-500"><Maximize2 size={16} /></div>
                    <select value={selectedResolution} onChange={(e) => setSelectedResolution(e.target.value as any)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]">{RESOLUTIONS.map(res => <option key={res} value={res}>{res}</option>)}</select>
                 </div>
              </div>
              <button onClick={handleToggleGeneration} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isGenerating ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}>
                {currentStatusIcon}
                {currentStatusLabel}
              </button>
          </div>
      </div>

      <div className="flex-1 flex flex-col items-center justify-start relative min-h-0 bg-[#020202] rounded-lg border border-zinc-900 shadow-inner overflow-hidden">
        <div className="absolute inset-0 bg-grid opacity-[0.05] pointer-events-none"></div>

        <div 
          ref={containerRef} 
          onMouseMove={resetControlsTimeout}
          className="relative w-full h-full flex flex-col bg-black shadow-2xl transition-all duration-500 group overflow-hidden shrink-0"
        >
            <div className="flex-1 relative flex items-center justify-center overflow-hidden border-b border-zinc-900" onClick={() => videoUrl && togglePlay()}>
                {!videoUrl && !isGenerating && (
                    <div className="z-10 text-center space-y-4 p-8">
                        <div className="w-16 h-16 bg-zinc-900/50 rounded-full flex items-center justify-center mx-auto border border-zinc-800">
                             <Film className="text-zinc-700 w-6 h-6" />
                        </div>
                        <p className="text-zinc-600 font-mono text-[10px] uppercase tracking-widest">Awaiting Render Signal</p>
                        {error && <p className="text-[#ff003c] text-[9px] font-mono mt-2 border border-[#ff003c]/20 p-2 bg-[#ff003c]/5">ERROR: {error}</p>}
                    </div>
                )}

                {isGenerating && (
                    <div className="z-20 scale-75">
                         <Loader text={status} />
                    </div>
                )}

                {videoUrl && !isGenerating && (
                    <>
                        <video 
                            key={videoUrl}
                            ref={videoRef}
                            src={videoUrl ? `${videoUrl}#t=0.001` : undefined}
                            onTimeUpdate={updateProgress}
                            onLoadedMetadata={updateProgress}
                            onPlay={() => { 
                                setIsPlaying(true);
                                if(videoRef.current) videoRef.current.playbackRate = playbackRate;
                            }}
                            onPause={() => setIsPlaying(false)}
                            className="w-full h-full object-contain pointer-events-none"
                            playsInline
                        />
                        <div className={`absolute top-3 left-3 z-30 flex gap-2 transition-opacity duration-500 ${controlsVisible ? 'opacity-100' : 'opacity-0'}`}>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-cyan-500/30 rounded-sm text-[8px] font-mono text-cyan-400 uppercase tracking-widest">Live_Playback</div>
                             <div className="bg-black/60 backdrop-blur-md px-2 py-0.5 border border-zinc-800 rounded-sm text-[8px] font-mono text-zinc-500 uppercase tracking-widest">{selectedResolution}</div>
                        </div>
                    </>
                )}
            </div>

            <div className={`w-full bg-[#020202] relative z-40 shrink-0 transition-all duration-500 ${videoUrl && controlsVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-full pointer-events-none'}`}>
                <div className="absolute top-0 left-0 w-full h-1 bg-zinc-800 hover:h-2 transition-all cursor-pointer z-50 group/progress">
                    <input 
                        type="range" 
                        min="0" max="100" step="0.1" 
                        value={playbackProgress} 
                        onChange={handleSeek} 
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="h-full bg-cyan-500 relative pointer-events-none" style={{ width: `${playbackProgress}%` }}>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-cyan-100 rounded-full shadow-[0_0_10px_#00f3ff] opacity-0 group-hover/progress:opacity-100 transition-opacity"></div>
                    </div>
                </div>

                <div className="flex items-center justify-between p-3">
                    <div className="flex-1 flex items-center gap-2">
                        {SPEEDS.map(s => (
                            <button 
                                key={s} 
                                onClick={(e) => { e.stopPropagation(); setPlaybackRate(s); }} 
                                className={`text-[10px] font-mono font-bold transition-all ${playbackRate === s ? 'text-cyan-400' : 'text-zinc-600 hover:text-zinc-400'}`}
                            >
                                {s}x
                            </button>
                        ))}
                    </div>

                    <div className="flex-2 flex items-center justify-center gap-6">
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime -= 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCcw size={20} /></button>
                        <button onClick={togglePlay} className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-transparent border-2 border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>
                            {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}
                        </button>
                        <button onClick={(e) => { e.stopPropagation(); if(videoRef.current) videoRef.current.currentTime += 5; }} className="text-zinc-500 hover:text-cyan-400 transition-colors"><RotateCw size={20} /></button>
                    </div>

                    <div className="flex-1 flex items-center justify-end gap-3">
                        <span className="text-[10px] font-mono text-zinc-600 min-w-[70px] text-right">{formatTime(currentTime)} / {formatTime(duration)}</span>
                        <button onClick={toggleMute} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isMuted ? <VolumeX size={18} /> : <Volume2 size={18} />}
                        </button>
                        <a href={videoUrl || '#'} download={`cine-render-${chapter.id}.mp4`} onClick={(e) => e.stopPropagation()} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            <Download size={18} />
                        </a>
                        <button onClick={toggleFullScreen} className="text-zinc-600 hover:text-cyan-400 transition-colors">
                            {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                        </button>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { NotebookItem, AppSettings, Chapter, MindMapNode } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, Settings2, Type, Loader2, ArrowUpDown, Network, Download, FileText, Share2, ZoomIn, ZoomOut, RefreshCw, Zap, X, Notebook as NotebookIcon, Play, Square, ChevronRight, ChevronDown, Minus, Plus, LogOut, FileDown } from 'lucide-react';
import { generateSpeech, generateMindMapStructure } from '../services/gemini';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import jsPDF from 'jspdf';
import { Loader } from './ui/Loader';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
  activeChapter?: Chapter | null;
  bookTitle?: string;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings, activeChapter, bookTitle }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  // Mind Map State
  const [isMindMapMode, setIsMindMapMode] = useState(false);
  const [mindMapData, setMindMapData] = useState<MindMapNode | null>(null);
  const [isGeneratingMap, setIsGeneratingMap] = useState(false);
  const [hasInitiatedMap, setHasInitiatedMap] = useState(false);
  const [collapsedNodeIds, setCollapsedNodeIds] = useState<Set<string>>(new Set());
  const [mapZoom, setMapZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const lastMousePos = useRef({ x: 0, y: 0 });
  const abortMapRef = useRef<boolean>(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const handleInitiateMindMap = async () => {
    if (isGeneratingMap) {
        abortMapRef.current = true;
        setIsGeneratingMap(false);
        return;
    }
    setIsGeneratingMap(true);
    setHasInitiatedMap(true);
    setMapZoom(1);
    setPan({ x: 0, y: 0 });
    setCollapsedNodeIds(new Set());
    abortMapRef.current = false;
    try {
        const title = activeChapter?.title || bookTitle || "Untitled Chapter";
        const context = activeChapter ? `Current Chapter: ${activeChapter.title}` : undefined;
        const structure = await generateMindMapStructure(filteredItems, title, context);
        if (abortMapRef.current) return;
        setMindMapData(structure);
        setIsMindMapMode(true);
    } catch (e) {
        if (!abortMapRef.current) console.error("Failed to generate mind map:", e);
    } finally {
        if (!abortMapRef.current) setIsGeneratingMap(false);
    }
  };

  const toggleNodeCollapse = (id: string, e?: React.MouseEvent) => {
      if (e) e.stopPropagation();
      setCollapsedNodeIds(prev => {
          const next = new Set(prev);
          if (next.has(id)) next.delete(id);
          else next.add(id);
          return next;
      });
  };

  // Panning Handlers
  const handleMapMouseDown = (e: React.MouseEvent) => {
    if (e.button !== 0) return; // Only left click
    setIsPanning(true);
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseMove = (e: React.MouseEvent) => {
    if (!isPanning) return;
    const dx = e.clientX - lastMousePos.current.x;
    const dy = e.clientY - lastMousePos.current.y;
    setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
    lastMousePos.current = { x: e.clientX, y: e.clientY };
  };

  const handleMapMouseUp = () => {
    setIsPanning(false);
  };

  // --- Export Functions ---

  const exportToDocx = async () => {
    if (!mindMapData) return;

    const childrenToParagraphs = (node: MindMapNode, level: number): Paragraph[] => {
        const paras = [
             new Paragraph({
                text: node.label,
                heading: level === 0 ? HeadingLevel.TITLE : level === 1 ? HeadingLevel.HEADING_1 : level === 2 ? HeadingLevel.HEADING_2 : undefined,
                bullet: level > 2 ? { level: 0 } : undefined,
             })
        ];
        if (node.children) {
            node.children.forEach(child => {
                paras.push(...childrenToParagraphs(child, level + 1));
            });
        }
        return paras;
    };

    const doc = new Document({
        sections: [{
            properties: {},
            children: childrenToParagraphs(mindMapData, 0),
        }],
    });

    const blob = await Packer.toBlob(doc);
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.docx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToXmind = async () => {
    if (!mindMapData) return;

    const zip = new JSZip();
    const mapNodeToTopic = (node: MindMapNode): any => {
        const topic: any = {
            "id": node.id,
            "title": node.label,
            "structureClass": "org.xmind.ui.map.unbalanced"
        };
        if (node.children && node.children.length > 0) {
            topic["children"] = {
                "attached": node.children.map(mapNodeToTopic)
            };
        }
        return topic;
    };

    const content = [
        {
            "id": "sheet-1",
            "class": "sheet",
            "title": "Sheet 1",
            "rootTopic": mapNodeToTopic(mindMapData)
        }
    ];

    zip.file("content.json", JSON.stringify(content));
    zip.file("manifest.json", JSON.stringify({
        "file-entries": { "content.json": {}, "metadata.json": {} }
    }));
    zip.file("metadata.json", "{}");

    const blob = await zip.generateAsync({ type: "blob" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mind-map-${activeChapter?.title || bookTitle || 'export'}.xmind`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportToPdf = () => {
    if (!mindMapData) return;
    const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'a4' });
    const startX = 50;
    const startY = 300;
    const drawNode = (node: MindMapNode, x: number, y: number, heightScope: number, depth: number) => {
        doc.setFontSize(Math.max(8, 16 - depth * 2));
        doc.setTextColor(0, 0, 0);
        doc.text(node.label, x, y);
        const textWidth = doc.getTextWidth(node.label);
        doc.setDrawColor(0, 243, 255);
        if (node.children && node.children.length > 0) {
            const childX = x + textWidth + 50;
            const totalChildren = node.children.length;
            const step = heightScope / totalChildren;
            let currentY = y - (heightScope / 2) + (step / 2);
            node.children.forEach(child => {
                doc.setLineWidth(0.5);
                doc.line(x + textWidth + 5, y - 2, childX - 5, currentY - 2);
                drawNode(child, childX, currentY, step, depth + 1);
                currentY += step;
            });
        }
    };
    drawNode(mindMapData, startX, startY, 500, 0);
    doc.save(`mind-map-${activeChapter?.title || bookTitle || 'export'}.pdf`);
  };

  // --- Visualization Helpers ---
  const renderTree = (node: MindMapNode, depth: number, x: number, y: number, heightScope: number): React.ReactNode => {
      const isCollapsed = collapsedNodeIds.has(node.id);
      const elements: React.ReactNode[] = [];
      const nodeColor = depth === 0 ? '#ff003c' : depth === 1 ? '#00f3ff' : '#e4e4e7';
      const fontSize = Math.max(10, 20 - depth * 4);
      const labelWidth = node.label.length * (fontSize * 0.6) + 30;

      elements.push(
          <g key={node.id} transform={`translate(${x},${y})`} className="cursor-pointer" onClick={(e) => node.children?.length ? toggleNodeCollapse(node.id, e) : null}>
              <rect x="-10" y="-15" width={labelWidth} height={32} fill="#050505" stroke={nodeColor} strokeWidth={depth === 0 ? 2 : 1} rx="4" />
              <text fill={nodeColor} fontSize={fontSize} fontFamily="monospace" x="5" y="6" pointerEvents="none">{node.label}</text>
              {node.children && node.children.length > 0 && (
                  <g transform={`translate(${labelWidth - 10}, 0)`}>
                      <circle r="8" fill="#0a0a0c" stroke={nodeColor} strokeWidth="1" />
                      {isCollapsed ? (
                          <path d="M -3 0 L 3 0 M 0 -3 L 0 3" stroke={nodeColor} strokeWidth="1.5" />
                      ) : (
                          <path d="M -3 0 L 3 0" stroke={nodeColor} strokeWidth="1.5" />
                      )}
                  </g>
              )}
          </g>
      );

      if (!isCollapsed && node.children && node.children.length > 0) {
          const childX = x + labelWidth + 100;
          const totalChildren = node.children.length;
          const step = heightScope / totalChildren;
          let currentY = y - (heightScope / 2) + (step / 2);

          node.children.forEach(child => {
              elements.push(
                  <path 
                    key={`link-${node.id}-${child.id}`}
                    d={`M ${x + labelWidth - 10} ${y} C ${x + labelWidth + 40} ${y}, ${x + labelWidth + 40} ${currentY}, ${childX - 10} ${currentY}`}
                    fill="none"
                    stroke={nodeColor}
                    strokeOpacity="0.3"
                    strokeWidth="1"
                  />
              );
              elements.push(renderTree(child, depth + 1, childX, currentY, step));
              currentY += step;
          });
      }
      return <>{elements}</>;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <div className="sticky top-0 z-[160] bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-4 flex-1 justify-end">
               <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                    <div className="flex items-center gap-1">
                        <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                        <select 
                            value={activeFilter} 
                            onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="all">ALL ITEMS</option>
                            <option value="word">WORDS</option>
                            <option value="phrase">PHRASES</option>
                            <option value="sentence">SENTENCES</option>
                        </select>
                    </div>
                    <div className="w-[1px] h-4 bg-zinc-700"></div>
                    <div className="flex items-center gap-1">
                        <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                        <select 
                            value={sortOrder} 
                            onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="newest">NEWEST</option>
                            <option value="oldest">OLDEST</option>
                            <option value="az">A-Z</option>
                            <option value="za">Z-A</option>
                        </select>
                    </div>
               </div>

               <button 
                  onClick={handleInitiateMindMap} 
                  disabled={filteredItems.length === 0} 
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 min-w-[120px] justify-center ${isGeneratingMap ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}
               >
                   {isGeneratingMap ? <Square size={14} fill="currentColor" /> : hasInitiatedMap ? <RefreshCw size={14} /> : <Play size={14} fill="currentColor" />}
                   {isGeneratingMap ? "STOP" : hasInitiatedMap ? "REGENERATE" : "INITIATE"}
               </button>
           </div>
       </div>

       {isMindMapMode ? (
           <div 
             className="flex-1 bg-[#050505] border border-zinc-800 rounded-lg relative overflow-hidden flex flex-col items-center justify-center animate-fade-in group" 
             ref={mapContainerRef}
             onMouseDown={handleMapMouseDown}
             onMouseMove={handleMapMouseMove}
             onMouseUp={handleMapMouseUp}
             onMouseLeave={handleMapMouseUp}
           >
               {/* Background Grid */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px] pointer-events-none"></div>

               {/* Floating Controls in Top Right */}
               <div className="absolute top-4 right-4 flex gap-2 z-50">
                    <button onClick={() => setMapZoom(z => Math.max(0.2, z - 0.1))} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0"><ZoomOut size={16}/></button>
                    <button onClick={() => setMapZoom(z => Math.min(3, z + 0.1))} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0"><ZoomIn size={16}/></button>

                    {/* Pertinent Export Buttons */}
                    <button onClick={exportToXmind} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to Xmind"><Network size={16}/></button>
                    <button onClick={exportToDocx} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to Docx"><FileText size={16}/></button>
                    <button onClick={exportToPdf} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#00f3ff] text-zinc-400 hover:text-[#00f3ff] rounded-full transition-colors shadow-lg shrink-0" title="Export to PDF"><FileDown size={16}/></button>

                    {/* Exit Map Button */}
                    <button onClick={() => setIsMindMapMode(false)} className="w-10 h-10 flex items-center justify-center bg-[#050505] border border-zinc-800 hover:border-[#ff003c] text-[#ff003c] rounded-full transition-colors shadow-lg shrink-0" title="Exit Map"><X size={16}/></button>
               </div>

               {isGeneratingMap ? (
                   <div className="flex flex-col items-center gap-4 z-10">
                       <Loader2 size={48} className="text-[#00f3ff] animate-spin" />
                       <p className="text-sm font-mono text-[#00f3ff] uppercase tracking-widest animate-pulse">Analyzing Neural Structures...</p>
                   </div>
               ) : mindMapData ? (
                   <div className="w-full h-full overflow-hidden flex items-center justify-center cursor-grab active:cursor-grabbing pointer-events-none">
                       <svg 
                        width="2400" 
                        height="1800" 
                        viewBox="-400 -900 2400 1800" 
                        style={{ 
                          transform: `translate(${pan.x}px, ${pan.y}px) scale(${mapZoom})`, 
                          transition: isPanning ? 'none' : 'transform 0.2s',
                          pointerEvents: 'auto'
                        }}
                       >
                           {renderTree(mindMapData, 0, 0, 0, 1600)}
                       </svg>
                   </div>
               ) : (
                   <div className="text-zinc-500 font-mono text-sm">FAILED_TO_RENDER_MAP</div>
               )}
           </div>
       ) : (
           <>
               {isGeneratingMap ? (
                   <div className="flex-1 flex flex-col items-center justify-center animate-fade-in">
                       <Loader text="GENERATING_MAP..." />
                   </div>
               ) : items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">{item.text}</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};

