export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  // Increased batch size to reduce total requests
  const batchSize = 30;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: DEFAULT_TEXT_MODEL,
        contents: {
          parts: [{ text: `Translate these sentences to ${targetLanguage}. Return a JSON array of strings only. \n\nSentences: ${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          thinkingConfig: { thinkingBudget: 0 },
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return safeJsonParse<string[]>(response.text || "[]");
    });
    results.push(...batchResult);
    if (i + batchSize < sentences.length) {
        // Longer wait between translation batches to stay under TPM limits
        await new Promise(r => setTimeout(r, 800));
    }
  }
  return results;
};

